func getEnv(key string) (string, error) {
	value, ok := os.LookupEnv(key)
	if !ok {
		return "", fmt.Errorf("environment variable %s not set", key)
	}
	return value, nil
}

func SeedUsers(db *gorm.DB, configService configsvc.Service) error {
	if configService == nil {
		return fmt.Errorf("configuration service unavailable")
	}
	config := configService.Current()

	adminPassword, err := getEnv("ADMIN_PASSWORD")
	if err != nil {
		return fmt.Errorf("retrieving ADMIN_PASSWORD: %w", err)
	}
	if adminPassword == "" {
		return fmt.Errorf("ADMIN_PASSWORD is set but empty")
	}

	// Check if the admin user already exists.
	var count int64
	db.Model(&models.User{}).Where("username = ?", "admin").Count(&count)
	if count == 0 {
		adminUser := models.User{
			PublicUser: models.PublicUser{
				Username:              "admin",
				DisplayName:           "Administrator",
				UserType:              "ADMIN",
				InitialAccountBalance: config.Economics.User.InitialAccountBalance,
				AccountBalance:        config.Economics.User.InitialAccountBalance,
				PersonalEmoji:         "NONE",
				Description:           "Administrator",
			},
			PrivateUser: models.PrivateUser{
				Email:  "admin@example.com",
				APIKey: "NONE",
			},
			MustChangePassword: true,
		}

		if err := adminUser.HashPassword(adminPassword); err != nil {
			return fmt.Errorf("hash admin password: %w", err)
		}

		if err := db.Create(&adminUser).Error; err != nil {
			return fmt.Errorf("create admin user: %w", err)
		}
	}

	return nil
}

func EnsureDBReady(db *gorm.DB, maxAttempts int) error {
	var err error
	for attempts := 1; attempts <= maxAttempts; attempts++ {
		// Attempt to perform a simple operation like pinging the database
		sqlDB, err := db.DB()
		if err != nil {
			log.Printf("Unable to get database/sql DB from GORM DB: %v", err)
			time.Sleep(time.Second * 5)
			continue
		}

		err = sqlDB.Ping()
		if err != nil {
			log.Printf("Failed to connect to the database, attempt %d/%d: %v", attempts, maxAttempts, err)
			time.Sleep(time.Second * 5) // Wait before retrying
			continue
		}

		log.Println("Database is ready.")
		return nil
	}

	return fmt.Errorf("database is not ready after %d attempts: %v", maxAttempts, err)
}

func SeedHomepage(db *gorm.DB, repoRoot string) error {
	var count int64
	if err := db.Model(&models.HomepageContent{}).
		Where("slug = ?", "home").Count(&count).Error; err != nil {
		return err
	}
	if count > 0 {
		return nil
	}

	// Use embedded content to avoid filesystem path issues
	var data []byte
	if len(defaultHomeMD) > 0 {
		data = defaultHomeMD
	} else {
		// Fallback only if embedding failed
		data = []byte("# Welcome to BrierFoxForecast\n\nThis is the seeded home page.")
	}

	// Create renderer for sanitization
	renderer := homepage.NewDefaultRenderer()

	// Since the content is pure HTML, treat it as HTML format
	htmlContent := string(data)

	// Sanitize the HTML directly (no markdown conversion needed)
	sanitizedHTML := renderer.SanitizeHTML(htmlContent)

	item := models.HomepageContent{
		Slug:     "home",
		Title:    "Home",
		Format:   "html", // Changed to html since content is pure HTML
		Markdown: "",     // Empty since we're using HTML format
		HTML:     sanitizedHTML,
		Version:  1,
	}

	return db.Create(&item).Error
}

package main

import (
	"log"
	"net/http"

	appenv "socialpredict/internal/app/env"
	appruntime "socialpredict/internal/app/runtime"
	authsvc "socialpredict/internal/service/auth"
	"socialpredict/migration"
	_ "socialpredict/migration/migrations" // <-- side-effect import: registers migrations via init()
	"socialpredict/seed"
	"socialpredict/server"
)

func main() {
	// Secure endpoint example
	http.Handle("/secure", authsvc.Authenticate(http.HandlerFunc(secureEndpoint)))

	// Load env (.env, .env.dev)
	if err := appenv.LoadDevFile(); err != nil {
		log.Printf("env: warning loading environment: %v", err)
	}

	dbCfg, err := appruntime.LoadDBConfigFromEnv()
	if err != nil {
		log.Fatalf("db config: %v", err)
	}

	db, err := appruntime.InitDB(dbCfg, appruntime.PostgresFactory{})
	if err != nil {
		log.Fatalf("db init: %v", err)
	}

	const MAX_ATTEMPTS = 20
	if err := seed.EnsureDBReady(db, MAX_ATTEMPTS); err != nil {
		log.Fatalf("database readiness check failed: %v", err)
	}

	if err := migration.MigrateDB(db); err != nil {
		log.Printf("migration: warning: %v", err)
	}

	configService, err := appruntime.LoadConfigService()
	if err != nil {
		log.Fatalf("config init: %v", err)
	}

	if err := seed.SeedUsers(db, configService); err != nil {
		log.Fatalf("seed users: %v", err)
	}
	if err := seed.SeedHomepage(db, "."); err != nil {
		log.Printf("seed homepage: warning: %v", err)
	}

	server.Start(openAPISpec, swaggerUIFS, db, configService)
}

